const STORAGE_KEY = 'neon-pac-achievements';

export class AchievementManager {
  achievements: Achievement[] = [];
  private newUnlocks: Achievement[] = [];

  // Callback for UI notification
  onUnlock?: (achievement: Achievement) => void;

  constructor() {
    this.loadAchievements();
  }

  private loadAchievements(): void {
    const saved = this.loadFromStorage();
    this.achievements = ACHIEVEMENT_DEFS.map((def) => ({
      ...def,
      unlocked: saved.has(def.id),
      unlockedAt: saved.get(def.id),
    }));
  }

  private loadFromStorage(): Map<string, number> {
    const map = new Map<string, number>();
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const data = JSON.parse(raw) as Record<string, number>;
        for (const [k, v] of Object.entries(data)) {
          map.set(k, v);
        }
      }
    } catch { /* ignore */ }
    return map;
  }

  private saveToStorage(): void {
    try {
      const data: Record<string, number> = {};
      for (const a of this.achievements) {
        if (a.unlocked && a.unlockedAt) {
          data[a.id] = a.unlockedAt;
        }
      }
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch { /* ignore */ }
  }

  unlock(id: string): boolean {
    const a = this.achievements.find((x) => x.id === id);
    if (!a || a.unlocked) return false;
    a.unlocked = true;
    a.unlockedAt = Date.now();
    this.newUnlocks.push(a);
    this.saveToStorage();
    this.onUnlock?.(a);
    return true;
  }

  popNewUnlock(): Achievement | undefined {
    return this.newUnlocks.shift();
  }

  hasNewUnlocks(): boolean {
    return this.newUnlocks.length > 0;
  }

  getUnlockedCount(): number {
    return this.achievements.filter((a) => a.unlocked).length;
  }

  getTotalCount(): number {
    return this.achievements.length;
  }

  getByCategory(cat: AchievementCategory): Achievement[] {
    return this.achievements.filter((a) => a.category === cat);
  }

  isUnlocked(id: string): boolean {
    return this.achievements.find((a) => a.id === id)?.unlocked ?? false;
  }

  // Get achievements as paginated list (8 per page)
  getPage(page: number, perPage = 8): { items: Achievement[]; totalPages: number } {
    const total = this.achievements.length;
    const totalPages = Math.ceil(total / perPage);
    const start = page * perPage;
    const items = this.achievements.slice(start, start + perPage);
    return { items, totalPages };
  }

  // Get unlocked achievements for display
  getUnlocked(): Achievement[] {
    return this.achievements.filter((a) => a.unlocked);
  }

  resetAll(): void {
    for (const a of this.achievements) {
      a.unlocked = false;
      a.unlockedAt = undefined;
    }
    this.newUnlocks = [];
    try { localStorage.removeItem(STORAGE_KEY); } catch { /* ignore */ }
  }
}

// === Neon Pac VR -- Audio Manager (procedural) ===

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private muted = false;

  private getCtx(): AudioContext {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = 0.3;
      this.masterGain.connect(this.ctx.destination);
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume();
    }
    return this.ctx;
  }

  private getMaster(): GainNode {
    this.getCtx();
    return this.masterGain!;
  }

  toggleMute(): boolean {
    this.muted = !this.muted;
    if (this.masterGain) {
      this.masterGain.gain.value = this.muted ? 0 : 0.3;
    }
    return this.muted;
  }

  playWaka(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'square';
    osc.frequency.setValueAtTime(440, t);
    osc.frequency.linearRampToValueAtTime(220, t + 0.06);
    gain.gain.setValueAtTime(0.15, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.08);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.1);
  }

  playPowerPellet(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    for (let i = 0; i < 4; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.08;
      osc.frequency.setValueAtTime(300 + i * 200, startTime);
      gain.gain.setValueAtTime(0.15, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.1);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.12);
    }
  }

  playGhostEat(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(800, t);
    osc.frequency.exponentialRampToValueAtTime(200, t + 0.3);
    gain.gain.setValueAtTime(0.2, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.35);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.4);
  }

  playDeath(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    for (let i = 0; i < 6; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.15;
      osc.frequency.setValueAtTime(600 - i * 80, startTime);
      osc.frequency.linearRampToValueAtTime(100, startTime + 0.12);
      gain.gain.setValueAtTime(0.15, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.14);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.16);
    }
  }

  playLevelComplete(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const notes = [523, 659, 784, 1047];
    for (let i = 0; i < notes.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.15;
      osc.frequency.setValueAtTime(notes[i], startTime);
      gain.gain.setValueAtTime(0.2, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.2);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.25);
    }
  }

  playGameStart(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const melody = [262, 330, 392, 523, 392, 330, 262];
    for (let i = 0; i < melody.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'square';
      const startTime = t + i * 0.12;
      osc.frequency.setValueAtTime(melody[i], startTime);
      gain.gain.setValueAtTime(0.1, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.1);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.12);
    }
  }

  playMenuSelect(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(660, t);
    gain.gain.setValueAtTime(0.1, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.08);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.1);
  }

  playFrightenedLoop(playing: boolean): void {
    // Simple one-shot siren blip for frightened state
    if (!playing) return;
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(200, t);
    osc.frequency.linearRampToValueAtTime(400, t + 0.2);
    osc.frequency.linearRampToValueAtTime(200, t + 0.4);
    gain.gain.setValueAtTime(0.06, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.4);
    osc.connect(gain);
    gain.connect(this.getMaster());
    osc.start(t);
    osc.stop(t + 0.45);
  }

  playAchievement(): void {
    const ctx = this.getCtx();
    const t = ctx.currentTime;
    const notes = [784, 988, 1175, 1319];
    for (let i = 0; i < notes.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const startTime = t + i * 0.1;
      osc.frequency.setValueAtTime(notes[i], startTime);
      gain.gain.setValueAtTime(0.12, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.15);
      osc.connect(gain);
      gain.connect(this.getMaster());
      osc.start(startTime);
      osc.stop(startTime + 0.18);
    }
  }
}

// === Neon Pac VR -- Stats Manager ===

export interface GameStats {
  totalGamesPlayed: number;
  totalScore: number;
  highScore: number;
  totalDotsEaten: number;
  totalPowerPelletsUsed: number;
  totalGhostsEaten: number;
  totalFruitsEaten: number;
  totalDeaths: number;
  totalLevelsCleared: number;
  highestLevel: number;
  totalTimePlayed: number; // seconds
  longestGameTime: number;
  bestLevelTime: number; // fastest level clear
  quadKills: number;
  tunnelUses: number;
  fruitsEatenByType: Record<string, number>;
  ghostsEatenByName: Record<string, number>;
  modesPlayed: Set<string>;
  consecutiveLevelsNoDeath: number;
  bestConsecutiveLevelsNoDeath: number;
}

const STORAGE_KEY = 'neon-pac-stats';

export class StatsManager {
  stats: GameStats;

  // Per-game tracking (reset each game)
  currentGameTime = 0;
  currentLevelTime = 0;
  currentLevelDeaths = 0;
  currentGameGhostsEaten = 0;
  currentGameFruitsEaten = 0;
  currentGameTunnelUses = 0;
  currentGameQuadKills = 0;
  currentGamePowerPelletsUsed = 0;
  currentGameGhostNames = new Set<string>();
  currentGameScore = 0;
  currentLevelPowerUsed = false;
  currentConsecutiveNoDeath = 0;
  currentFruitTypes = new Set<string>();

  constructor() {
    this.stats = this.load();
  }

  private load(): GameStats {
    const defaults: GameStats = {
      totalGamesPlayed: 0,
      totalScore: 0,
      highScore: 0,
      totalDotsEaten: 0,
      totalPowerPelletsUsed: 0,
      totalGhostsEaten: 0,
      totalFruitsEaten: 0,
      totalDeaths: 0,
      totalLevelsCleared: 0,
      highestLevel: 1,
      totalTimePlayed: 0,
      longestGameTime: 0,
      bestLevelTime: Infinity,
      quadKills: 0,
      tunnelUses: 0,
      fruitsEatenByType: {},
      ghostsEatenByName: {},
      modesPlayed: new Set<string>(),
      consecutiveLevelsNoDeath: 0,
      bestConsecutiveLevelsNoDeath: 0,
    };

    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const data = JSON.parse(raw);
        return {
          ...defaults,
          ...data,
          modesPlayed: new Set(data.modesPlayed ?? []),
        };
      }
    } catch { /* ignore */ }
    return defaults;
  }

  save(): void {
    try {
      const data = {
        ...this.stats,
        modesPlayed: Array.from(this.stats.modesPlayed),
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch { /* ignore */ }
  }

  startGame(mode: string): void {
    this.stats.totalGamesPlayed++;
    this.stats.modesPlayed.add(mode);
    this.currentGameTime = 0;
    this.currentLevelTime = 0;
    this.currentLevelDeaths = 0;
    this.currentGameGhostsEaten = 0;
    this.currentGameFruitsEaten = 0;
    this.currentGameTunnelUses = 0;
    this.currentGameQuadKills = 0;
    this.currentGamePowerPelletsUsed = 0;
    this.currentGameGhostNames.clear();
    this.currentGameScore = 0;
    this.currentLevelPowerUsed = false;
    this.currentConsecutiveNoDeath = 0;
    this.currentFruitTypes.clear();
    this.save();
  }

  recordDotEaten(): void {
    this.stats.totalDotsEaten++;
  }

  recordPowerPellet(): void {
    this.stats.totalPowerPelletsUsed++;
    this.currentGamePowerPelletsUsed++;
    this.currentLevelPowerUsed = true;
  }

  recordGhostEaten(ghostName: string, chainCount: number): void {
    this.stats.totalGhostsEaten++;
    this.currentGameGhostsEaten++;
    this.currentGameGhostNames.add(ghostName);
    this.stats.ghostsEatenByName[ghostName] = (this.stats.ghostsEatenByName[ghostName] ?? 0) + 1;
    if (chainCount >= 4) {
      this.stats.quadKills++;
      this.currentGameQuadKills++;
    }
  }

  recordFruitEaten(fruitType: string): void {
    this.stats.totalFruitsEaten++;
    this.currentGameFruitsEaten++;
    this.currentFruitTypes.add(fruitType);
    this.stats.fruitsEatenByType[fruitType] = (this.stats.fruitsEatenByType[fruitType] ?? 0) + 1;
  }

  recordDeath(): void {
    this.stats.totalDeaths++;
    this.currentLevelDeaths++;
    this.currentConsecutiveNoDeath = 0;
  }

  recordTunnelUse(): void {
    this.stats.tunnelUses++;
    this.currentGameTunnelUses++;
  }

  recordLevelClear(levelTime: number): void {
    this.stats.totalLevelsCleared++;
    if (levelTime < this.stats.bestLevelTime) {
      this.stats.bestLevelTime = levelTime;
    }
    if (this.currentLevelDeaths === 0) {
      this.currentConsecutiveNoDeath++;
      if (this.currentConsecutiveNoDeath > this.stats.bestConsecutiveLevelsNoDeath) {
        this.stats.bestConsecutiveLevelsNoDeath = this.currentConsecutiveNoDeath;
      }
    }
    this.currentLevelTime = 0;
    this.currentLevelDeaths = 0;
    this.currentLevelPowerUsed = false;
    this.save();
  }

  recordGameEnd(score: number, level: number): void {
    this.currentGameScore = score;
    this.stats.totalScore += score;
    if (score > this.stats.highScore) {
      this.stats.highScore = score;
    }
    if (level > this.stats.highestLevel) {
      this.stats.highestLevel = level;
    }
    if (this.currentGameTime > this.stats.longestGameTime) {
      this.stats.longestGameTime = this.currentGameTime;
    }
    this.stats.totalTimePlayed += this.currentGameTime;
    this.save();
  }

  updateTime(delta: number): void {
    this.currentGameTime += delta;
    this.currentLevelTime += delta;
  }

  getFormattedTime(seconds: number): string {
    const m = Math.floor(seconds / 60);
    const s = Math.floor(seconds % 60);
    return `${m}:${s.toString().padStart(2, '0')}`;
  }

  reset(): void {
    try { localStorage.removeItem(STORAGE_KEY); } catch { /* ignore */ }
    this.stats = this.load();
  }
}

// === Neon Pac VR -- Particle Effects System ===

import {
  Group,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Color,
  Vector3,
} from '@iwsdk/core';

interface Particle {
  mesh: Mesh;
  velocity: Vector3;
  life: number;
  maxLife: number;
}

export class ParticleManager {
  private particles: Particle[] = [];
  private group: Group;
  private geo: SphereGeometry;
  private pool: Mesh[] = [];

  constructor(parent: Group) {
    this.group = new Group();
    parent.add(this.group);
    this.geo = new SphereGeometry(0.008, 4, 3);
  }

  // Burst of particles at position with given color
  burst(position: Vector3, color: number, count = 12, speed = 0.5): void {
    for (let i = 0; i < count; i++) {
      const mesh = this.getMesh(color);
      mesh.position.copy(position);
      mesh.visible = true;

      const angle = (Math.PI * 2 * i) / count + (Math.random() - 0.5) * 0.5;
      const elevation = (Math.random() - 0.3) * Math.PI;
      const spd = speed * (0.5 + Math.random() * 0.5);

      const velocity = new Vector3(
        Math.cos(angle) * Math.cos(elevation) * spd,
        Math.sin(elevation) * spd * 0.5 + 0.2,
        Math.sin(angle) * Math.cos(elevation) * spd,
      );

      const life = 0.5 + Math.random() * 0.5;
      this.particles.push({ mesh, velocity, life, maxLife: life });
    }
  }

  // Score popup effect — spray upward
  scorePopup(position: Vector3, color: number): void {
    this.burst(position, color, 8, 0.3);
  }

  // Ghost eat effect — big burst
  ghostEatEffect(position: Vector3, ghostColor: number): void {
    this.burst(position, ghostColor, 20, 0.8);
    this.burst(position, 0xffffff, 6, 0.4);
  }

  // Death effect
  deathEffect(position: Vector3): void {
    this.burst(position, 0xffff00, 24, 0.6);
    this.burst(position, 0xff4400, 12, 0.4);
  }

  // Level complete celebration
  levelCompleteEffect(position: Vector3): void {
    const colors = [0xff0000, 0x00ff00, 0x0066ff, 0xffff00, 0xff00ff, 0x00ffff];
    for (const c of colors) {
      this.burst(position, c, 6, 0.7);
    }
  }

  // Fruit eat effect
  fruitEffect(position: Vector3, fruitColor: number): void {
    this.burst(position, fruitColor, 16, 0.6);
    this.burst(position, 0xffffff, 4, 0.3);
  }

  update(delta: number): void {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= delta;

      if (p.life <= 0) {
        p.mesh.visible = false;
        this.pool.push(p.mesh);
        this.particles.splice(i, 1);
        continue;
      }

      // Move
      p.mesh.position.x += p.velocity.x * delta;
      p.mesh.position.y += p.velocity.y * delta;
      p.mesh.position.z += p.velocity.z * delta;

      // Gravity
      p.velocity.y -= 1.5 * delta;

      // Fade out
      const t = p.life / p.maxLife;
      const scale = t * 1.5;
      p.mesh.scale.setScalar(scale);
      const mat = p.mesh.material as MeshBasicMaterial;
      mat.opacity = t;
    }
  }

  private getMesh(color: number): Mesh {
    if (this.pool.length > 0) {
      const mesh = this.pool.pop()!;
      (mesh.material as MeshBasicMaterial).color.setHex(color);
      (mesh.material as MeshBasicMaterial).opacity = 1;
      mesh.scale.setScalar(1);
      return mesh;
    }

    const mat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 1,
    });
    const mesh = new Mesh(this.geo, mat);
    this.group.add(mesh);
    return mesh;
  }
}

// === Neon Pac VR -- Particle ECS System ===

import { createSystem, Vector3 } from '@iwsdk/core';
import { ParticleManager } from './particles';
import { GameManager } from './game';
import { GameState, FRUIT_COLORS, FruitType, GHOST_COLORS, GhostName, CELL_SIZE } from './types';

export class ParticleSystem extends createSystem({}) {
  private particles!: ParticleManager;
  private game!: GameManager;
  private lastState: GameState = GameState.MENU;
  private lastScore = 0;
  private lastGhostsEaten = 0;
  private lastFruitsEaten = 0;

  setRefs(refs: { particles: ParticleManager; game: GameManager }): void {
    this.particles = refs.particles;
    this.game = refs.game;
  }

  update(delta: number, _time: number): void {
    if (!this.particles || !this.game) return;

    this.particles.update(delta);

    const state = this.game.state;

    // Detect ghost eaten
    const totalGhosts = this.game.statsManager.stats.totalGhostsEaten;
    if (totalGhosts > this.lastGhostsEaten) {
      this.lastGhostsEaten = totalGhosts;
      // Find the ghost that was just eaten
      for (const ghost of this.game.ghosts) {
        if (ghost.mode === 'eaten' as any) {
          const pos = ghost.mesh.position.clone();
          pos.y += 0.03;
          const color = ghost.originalColor;
          this.particles.ghostEatEffect(pos, color);
          break;
        }
      }
    }

    // Detect fruit eaten
    const totalFruits = this.game.statsManager.stats.totalFruitsEaten;
    if (totalFruits > this.lastFruitsEaten) {
      this.lastFruitsEaten = totalFruits;
      const pos = this.game.pacMesh.position.clone();
      pos.y += 0.03;
      this.particles.fruitEffect(pos, 0x44ff44);
    }

    // Detect state changes
    if (state !== this.lastState) {
      if (state === GameState.DYING) {
        const pos = this.game.pacMesh.position.clone();
        this.particles.deathEffect(pos);
      }
      if (state === GameState.LEVEL_COMPLETE) {
        const pos = this.game.pacMesh.position.clone();
        pos.y += 0.1;
        this.particles.levelCompleteEffect(pos);
      }
      this.lastState = state;
    }

    this.lastScore = this.game.score;
  }
}

